$ErrorActionPreference='Stop'
$out=Join-Path $PSScriptRoot 'NovaShop_FinalYear_Project_Presentation.pptx'
$pp=New-Object -ComObject PowerPoint.Application
$pp.Visible=-1
$deck=$pp.Presentations.Add()
function Color($r,$g,$b){$r+256*$g+65536*$b}
$cream=Color 249 247 241;$ink=Color 27 42 37;$clay=Color 216 134 104;$sage=Color 205 220 198;$sand=Color 237 229 216;$white=Color 255 255 255;$muted=Color 96 108 103
function Slide($dark=$false){$s=$deck.Slides.Add($deck.Slides.Count+1,12);$s.Background.Fill.ForeColor.RGB=$(if($dark){$ink}else{$cream});$s}
function Rect($s,$x,$y,$w,$h,$c){$a=$s.Shapes.AddShape(1,$x,$y,$w,$h);$a.Fill.ForeColor.RGB=$c;$a.Line.Visible=0;$a}
function Txt($s,$t,$x,$y,$w,$h,$size,$c,$bold=$false){$a=$s.Shapes.AddTextbox(1,$x,$y,$w,$h);$a.TextFrame.TextRange.Text=$t;$a.TextFrame.TextRange.Font.Name='Aptos';$a.TextFrame.TextRange.Font.Size=$size;$a.TextFrame.TextRange.Font.Color.RGB=$c;$a.TextFrame.TextRange.Font.Bold=$(if($bold){-1}else{0});$a}
function Head($s,$n,$t,$sub){Txt $s ("0$n") 55 35 50 15 9 $clay $true|Out-Null;Txt $s $t 55 60 750 38 28 $ink $true|Out-Null;Txt $s $sub 55 108 760 25 12 $muted|Out-Null}
function Card($s,$title,$body,$x,$y,$w,$h,$color){Rect $s $x $y $w $h $color|Out-Null;Txt $s $title ($x+18) ($y+18) ($w-36) 20 15 $ink $true|Out-Null;Txt $s $body ($x+18) ($y+50) ($w-36) ($h-58) 10 $muted|Out-Null}
function Screen($s,$x,$y,$w,$h,$label){Rect $s $x $y $w $h $white|Out-Null;Rect $s $x $y $w 25 $ink|Out-Null;Txt $s 'nova shop' ($x+14) ($y+7) 80 12 8 $white $true|Out-Null;Txt $s $label ($x+110) ($y+7) 100 12 7 $white|Out-Null;Rect $s ($x+12) ($y+40) ($w-24) 75 $clay|Out-Null;Txt $s 'Small things. Big joy.' ($x+25) ($y+62) 180 24 16 $ink $true|Out-Null;for($i=0;$i -lt 3;$i++){Rect $s ($x+14+$i*($w-34)/3) ($y+132) (($w-45)/3) 62 $sand|Out-Null;Txt $s @('Headphones','Daypack','Pour Set')[$i] ($x+18+$i*($w-34)/3) ($y+201) 70 12 7 $ink $true|Out-Null}}

